mapper.select:
SELECT id, order_no, user_id, total_amount, status, create_time, update_time
FROM `order`
WHERE id = #{id}

SELECT id, order_no, user_id, total_amount, status, create_time, update_time
FROM `order`
WHERE order_no = #{orderNo}

SELECT id, order_no, user_id, total_amount, status, create_time, update_time
FROM `order`
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}
